import{_ as s,c as a,o as n,a4 as e}from"./chunks/framework.HaEZziQ1.js";const b=JSON.parse('{"title":"EthersJs学习","description":"","frontmatter":{},"headers":[],"relativePath":"Document/Web3学习/EthersJs学习.md","filePath":"Document/Web3学习/EthersJs学习.md","lastUpdated":1709668918000}'),l={name:"Document/Web3学习/EthersJs学习.md"},p=e(`<h1 id="ethersjs学习" tabindex="-1">EthersJs学习 <a class="header-anchor" href="#ethersjs学习" aria-label="Permalink to &quot;EthersJs学习&quot;">​</a></h1><h2 id="简单介绍ethers-js" tabindex="-1">简单介绍Ethers.js <a class="header-anchor" href="#简单介绍ethers-js" aria-label="Permalink to &quot;简单介绍Ethers.js&quot;">​</a></h2><p>Ethers.js与Web3.js一样，都是以太坊标准JavaScript API库，Ethers.js最初是为了ethers.io设计，后来拓展为一个开放的JS API库，与Web3.js相同的是，Ethers.js同样可以与Moonbeam进行正常交互，这得益于Moonbeam是一个完全兼容以太坊EVM的智能合约平台；而与Web3.js不同的是，Ethers.js在使用时不需要过多的回调函数，而且可以搭配Hardhat工具是的语法得到进一步的优化</p><p><strong>Ethers.js</strong> 的优势之处在于紧凑小巧，同时又包含大量测试案例。它提供实用的“新手入门”文档，因此新用户也可使用。许多开发者评价 ethers.js 使用起来“简单”、“直观”，并且该库在近两年越来越受欢迎，下载量和在项目中的使用量也不断增加。</p><h2 id="ethers-js相关网站" tabindex="-1">Ethers.js相关网站 <a class="header-anchor" href="#ethers-js相关网站" aria-label="Permalink to &quot;Ethers.js相关网站&quot;">​</a></h2><p>官方GitHub开源库：<a href="https://github.com/ethers-io/ethers.js" target="_blank" rel="noreferrer">ethers-io/ethers.js: Complete Ethereum library and wallet implementation in JavaScript. (github.com)</a></p><p>ethers.js官网文档：<a href="https://docs.ethers.org/v6/" target="_blank" rel="noreferrer">https://docs.ethers.org/v6/</a></p><p>官网：<a href="https://ethers.org/" target="_blank" rel="noreferrer">ethers</a></p><p><strong>ethers.js中文文档</strong>：<a href="https://learnblockchain.cn/ethers_v5/" target="_blank" rel="noreferrer">ethers.js 中文文档 (learnblockchain.cn)</a></p><p><a href="https://github.com/WTFAcademy/WTF-Ethers" target="_blank" rel="noreferrer">WTFAcademy/WTF-Ethers: 我最近在重新学ethers.js，巩固一下细节，也写一个“WTF Ethers.js极简入门”，供小白们使用，每周更新1-3讲。 (github.com)</a></p><h2 id="ethers-js入门" tabindex="-1">Ethers.js入门 <a class="header-anchor" href="#ethers-js入门" aria-label="Permalink to &quot;Ethers.js入门&quot;">​</a></h2><p><a href="https://wtf.academy/ether-start/" target="_blank" rel="noreferrer">Ethers.js入门 | WTF Academy</a></p><h2 id="ethers-js-有四个模块-构成应用程序编程界面-api" tabindex="-1">ethers.js 有四个模块，构成应用程序编程界面 (API) <a class="header-anchor" href="#ethers-js-有四个模块-构成应用程序编程界面-api" aria-label="Permalink to &quot;ethers.js 有四个模块，构成应用程序编程界面 (API)&quot;">​</a></h2><ol><li>Ethers.provider</li><li>Ethers.contract</li><li>Ethers.utils</li><li>Ethers.wallets</li></ol><h3 id="ethers-provider-有什么作用" tabindex="-1">ethers.provider 有什么作用？ <a class="header-anchor" href="#ethers-provider-有什么作用" aria-label="Permalink to &quot;ethers.provider 有什么作用？&quot;">​</a></h3><p>Ethers.provider 的作用是封装与以太坊区块链的连接。它可以用于签发查询和发送已签名的交易，这将改变区块链的状态。下面显示了三个说明性示例：</p><ul><li><em>ethers.providers.InfuraProvider</em> 的作用是使你可以与 Infura 托管的以太坊节点网络建立连接</li><li><em>ethers.provider.getBalance</em> 将为你获取区块链中某个地址或区块的以太坊余额</li><li><em>ethers.provider.resolve</em> 将解析传递到以太坊地址的以太坊名称服务 (ENS) 名称(通过“承诺”— 如果你刚接触 JavaScript，我们建议你阅读有关承诺[7]的更多内容，它们的作用是在未来某个时间点对它们进行计算时可以返回数据)。</li></ul><p>注：<em>web3.js</em> 也有服务于此目的的提供商，位于 <em>web3</em> 基础模块中。<em>Ethers.js</em> 和 <em>web3.js</em> 的组织方式截然不同，因此尽管两个库的功能非常相似，但模块间并非总是能清晰对应。</p><h3 id="ethers-contract-有什么作用" tabindex="-1">ethers.contract 有什么作用？ <a class="header-anchor" href="#ethers-contract-有什么作用" aria-label="Permalink to &quot;ethers.contract 有什么作用？&quot;">​</a></h3><p>Ethers.contract 的作用是部署智能合约并与它交互。具体来说，该模块中的函数用于侦听从智能合约发射的事件、调用智能合约提供的函数、获取有关智能合约的信息，以及部署智能合约。下面显示了两个说明性示例：</p><ul><li><em>ethers.ContractFactory.fromSolidity</em> 从 Solidity 编译器的编译器输出或从 Truffle 生成的 JSON 文件创建一个用于部署智能合约的“工厂”。<em>ethers.Contract</em> 使你可以与已部署的智能合约进行交互。</li></ul><h3 id="ethers-utils-有什么作用" tabindex="-1">ethers.utils 有什么作用？ <a class="header-anchor" href="#ethers-utils-有什么作用" aria-label="Permalink to &quot;ethers.utils 有什么作用？&quot;">​</a></h3><p>Ethers.utils 提供用于格式化数据和处理用户输入的实用程序函数。Ethers.utils 的作用方式与 web3-utils 相似，能够简化去中心化应用的构建流程。下面提供了三个示例：</p><ul><li><em>ethers.utils.getContractAddress</em> 从用于部署智能合约的交易中提取智能合约地址</li><li><em>ethers.utils.computeAddress</em> 通过传递与地址相关的公钥或私钥的函数来计算地址 <em>ethers.utils.formatEther</em> 将所传递的 Wei 金额转换为 Ether 十进制字符串格式</li></ul><h3 id="ethers-wallet-有什么作用" tabindex="-1">ethers.wallet 有什么作用？ <a class="header-anchor" href="#ethers-wallet-有什么作用" aria-label="Permalink to &quot;ethers.wallet 有什么作用？&quot;">​</a></h3><p>Ethers.wallet 提供的功能与我们目前讨论过的其他模块截然不同。Ethers.wallet 的作用是使你可以与现有钱包(以太坊地址)建立连接、创建新钱包以及对交易签名。下面提供了三个示例：</p><ul><li><em>ethers.wallet.createRandom</em> 将创建随机新账户。</li><li><em>ethers.wallet.sign</em> 将对交易签名并将已签名的交易返回为十六进制字符串的形式(通过“承诺”— 如果你刚接触 JavaScript，我们建议你阅读有关承诺[8]的更多内容，它们的作用是在未来某个时间点对它们进行计算时可以返回数据)。</li><li><em>ethers.wallet.getBalance</em> 将为我们提供钱包地址的以太坊余额。</li></ul><h2 id="ethers-js-hardhat-的安装与常用api介绍" tabindex="-1">Ethers.js(Hardhat)的安装与常用API介绍 <a class="header-anchor" href="#ethers-js-hardhat-的安装与常用api介绍" aria-label="Permalink to &quot;Ethers.js(Hardhat)的安装与常用API介绍&quot;">​</a></h2><h3 id="一、ethers-js-hardhat-的安装" tabindex="-1">一、Ethers.js(Hardhat)的安装 <a class="header-anchor" href="#一、ethers-js-hardhat-的安装" aria-label="Permalink to &quot;一、Ethers.js(Hardhat)的安装&quot;">​</a></h3><p>Ethers.js的安装分为两种，一种为直接使用命令行安装，另一种为通过Hardhat间接安装（配合Hardhat使用），推荐第二种通过Hardhat👷的方式使用Ethers.js（安装Hardhat时通过hardhat-ethers插件安装经过包装后的Ethers.js）</p><p>安装步骤如下：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;"># 安装命令</span></span>
<span class="line"><span style="color:#61AFEF;">npm</span><span style="color:#98C379;"> install</span><span style="color:#D19A66;"> --save</span><span style="color:#98C379;"> ethers</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;"># 安装步骤</span></span>
<span class="line"><span style="color:#61AFEF;">npm</span><span style="color:#98C379;"> init</span></span>
<span class="line"><span style="color:#61AFEF;">npm</span><span style="color:#98C379;"> install</span><span style="color:#D19A66;"> --save-dev</span><span style="color:#98C379;"> hardhat</span></span>
<span class="line"><span style="color:#61AFEF;">npx</span><span style="color:#98C379;"> hardhat</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>默认下载最新版本包。</p><h3 id="引入依赖" tabindex="-1">引入依赖 <a class="header-anchor" href="#引入依赖" aria-label="Permalink to &quot;引入依赖&quot;">​</a></h3><p><strong>Node.js环境</strong>：</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#61AFEF;">const</span><span style="color:#98C379;"> {</span><span style="color:#98C379;"> ethers</span><span style="color:#98C379;"> }</span><span style="color:#98C379;"> =</span><span style="color:#98C379;"> require</span><span style="color:#ABB2BF;">(</span><span style="color:#61AFEF;">&quot;ethers&quot;</span><span style="color:#ABB2BF;">); </span><span style="color:#61AFEF;">//</span><span style="color:#98C379;"> node.js</span><span style="color:#98C379;"> require</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">import</span><span style="color:#98C379;"> {</span><span style="color:#98C379;"> ethers</span><span style="color:#98C379;"> }</span><span style="color:#98C379;"> from</span><span style="color:#98C379;"> &quot;ethers&quot;</span><span style="color:#ABB2BF;">;  </span><span style="color:#61AFEF;">//</span><span style="color:#98C379;"> ES6</span><span style="color:#98C379;"> or</span><span style="color:#98C379;"> TypeScript</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>网页浏览器环境</strong>：</p><p>对于快速演示或原型设计，您可以从 CDN 将其加载到 Web 应用程序中：</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#56B6C2;">&lt;!--</span><span style="color:#E5C07B;"> ES6</span><span style="color:#C678DD;"> in</span><span style="color:#E06C75;"> the</span><span style="color:#E06C75;"> Browser</span><span style="color:#56B6C2;"> --&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">script</span><span style="color:#D19A66;font-style:italic;"> type</span><span style="color:#56B6C2;">=</span><span style="color:#98C379;">&quot;module&quot;</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">    import </span><span style="color:#C678DD;">{</span><span style="color:#E06C75;"> ethers</span><span style="color:#C678DD;"> }</span><span style="color:#ABB2BF;"> from &quot;https://cdn.ethers.io/lib/ethers-5.2.esm.min.js&quot;;</span></span>
<span class="line"><span style="color:#ABB2BF;">    // Your code here...</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">&lt;/</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#56B6C2;">&lt;!--</span><span style="color:#61AFEF;"> ES3</span><span style="color:#ABB2BF;"> (</span><span style="color:#E5C07B;">UMD</span><span style="color:#ABB2BF;">) </span><span style="color:#C678DD;">in</span><span style="color:#E06C75;"> the</span><span style="color:#E06C75;"> Browser</span><span style="color:#56B6C2;"> --&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">&lt;</span><span style="color:#E06C75;">script</span><span style="color:#D19A66;font-style:italic;"> src</span><span style="color:#56B6C2;">=</span><span style="color:#98C379;">&quot;https://cdn.ethers.io/lib/ethers-5.6.umd.min.js&quot;</span></span>
<span class="line"><span style="color:#D19A66;font-style:italic;">type</span><span style="color:#56B6C2;">=</span><span style="color:#98C379;">&quot;application/javascript&quot;</span><span style="color:#ABB2BF;">&gt;&lt;/</span><span style="color:#E06C75;">script</span><span style="color:#ABB2BF;">&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><blockquote><p>将 ethers 库复制到您自己的网络服务器并自己提供服务通常是更好的做法（出于安全原因）。</p></blockquote><h3 id="二、常用api介绍" tabindex="-1">二、常用API介绍 <a class="header-anchor" href="#二、常用api介绍" aria-label="Permalink to &quot;二、常用API介绍&quot;">​</a></h3><p>Ethers.js库中的API主要由4大部分组成：<strong>Providers</strong>，<strong>Signers</strong>，<strong>Contract Interaction</strong>，<strong>Utilities</strong></p><table><thead><tr><th><strong>Provider</strong></th><th>Provider（在ethers中）是一个为以太坊网络连接提供抽象的类。它提供对区块链及其状态的只读访问。</th></tr></thead><tbody><tr><td><strong>Signer</strong></td><td>签名者是一个（通常）以某种方式直接或间接访问私钥的类，它可以签署消息和交易以授权网络向您的帐户收取以太币，执行操作。</td></tr><tr><td><strong>Contract</strong></td><td>合约是一种抽象，表示与以太坊网络上特定合约的连接，因此应用程序可以像使用普通 JavaScript 对象一样使用它。</td></tr><tr><td><strong>Utilities</strong></td><td></td></tr></tbody></table><h4 id="_1-provider" tabindex="-1">1. Provider <a class="header-anchor" href="#_1-provider" aria-label="Permalink to &quot;1. Provider&quot;">​</a></h4><p>Provider是以太坊网络连接的抽象，其为标准以太坊节点功能提供简洁、一致的接口</p><p>在Provider中比较常用的方法为JsonRpcProvider，该方法允许通过JSON-RPC的方式连接某一个节点网络</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// new ethers.providers.JsonRpcProvider([urlOrConnectionInfo[, networkish]])</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> provider</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#E5C07B;"> ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">providers</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">JsonRpcProvider</span><span style="color:#ABB2BF;">(</span></span>
<span class="line"><span style="color:#98C379;">    &#39;https://rpc.api.moonbase.moonbeam.network&#39;</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#ABB2BF;">    {</span></span>
<span class="line"><span style="color:#E06C75;">        chainId</span><span style="color:#ABB2BF;">: </span><span style="color:#D19A66;">1287</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#E06C75;">        name</span><span style="color:#ABB2BF;">: </span><span style="color:#98C379;">&#39;moonbase-alpha&#39;</span></span>
<span class="line"><span style="color:#ABB2BF;">    }</span></span>
<span class="line"><span style="color:#ABB2BF;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>在上面的代码示例中，通过JsonRpcProvider的方式，连接到了Moonbase Alpha测试网中，在其中不止可以定义url参数，还可以定义该网络的chainId与name等信息</p><h4 id="_2-signers" tabindex="-1">2. Signers <a class="header-anchor" href="#_2-signers" aria-label="Permalink to &quot;2. Signers&quot;">​</a></h4><p>Signer是以太坊账户的抽象，可用于对消息和交易进行签名，并将签名过的交易发送到以太坊网络以执行状态更改操作</p><p>在Signer中比较常用的方法为Wallet，只有Wallet可以使用私钥对交易和信息进行签名</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// new ethers.Wallet(privateKey[, provider])</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> alice</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#E5C07B;"> ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">Wallet</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">privateKeyAlice</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">provider</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> bob</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#E5C07B;"> ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">Wallet</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">privateKeyBob</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">provider</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> txReceipt</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> await</span><span style="color:#E5C07B;"> alice</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">sendTransaction</span><span style="color:#ABB2BF;">({</span></span>
<span class="line"><span style="color:#E06C75;">    to</span><span style="color:#ABB2BF;">: </span><span style="color:#E5C07B;">bob</span><span style="color:#ABB2BF;">.</span><span style="color:#E06C75;">address</span><span style="color:#ABB2BF;">,</span></span>
<span class="line"><span style="color:#E06C75;">    value</span><span style="color:#ABB2BF;">: </span><span style="color:#E5C07B;">ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">utils</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">parseEther</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;1.0&#39;</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#ABB2BF;">});</span></span>
<span class="line"><span style="color:#C678DD;">await</span><span style="color:#E5C07B;"> txReceipt</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">wait</span><span style="color:#ABB2BF;">();</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>在上面的代码示例中，使用Wallet定义了alice与bob两个Signer，接下来alice调用方法sendTransaction()方法向bob发起交易，转移了1 ether的token</p><h4 id="_3-contract-interaction" tabindex="-1">3. Contract Interaction <a class="header-anchor" href="#_3-contract-interaction" aria-label="Permalink to &quot;3. Contract Interaction&quot;">​</a></h4><p>部署合约与生成合约实例离不开下面介绍的两个方法：ContractFactory()与Contract，具体方法直接看下面的代码示例接口</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// deploy contract</span></span>
<span class="line"><span style="color:#C678DD;">new</span><span style="color:#E5C07B;"> ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">ContractFactory</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">interface</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">bytecode</span><span style="color:#ABB2BF;">[, </span><span style="color:#E06C75;">signer</span><span style="color:#ABB2BF;">])</span></span>
<span class="line"><span style="color:#E5C07B;">contractFactory</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">deploy</span><span style="color:#ABB2BF;">(..</span><span style="color:#E06C75;">args</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#E5C07B;">contract</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">deployed</span><span style="color:#ABB2BF;">()</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// generate contract instance</span></span>
<span class="line"><span style="color:#C678DD;">new</span><span style="color:#E5C07B;"> ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">Contract</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">address</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">abi</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">signerOrProvider</span><span style="color:#ABB2BF;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>其中ContracFactory中的interface参数代表合约的abi 使用Hardhat编译过后的合约，其abi与bytecode等编译信息都存放在了项目根目录下的artifacts/contracts/CONTRACT_NAME.json文件中</p><h4 id="_4-utilities" tabindex="-1">4. Utilities <a class="header-anchor" href="#_4-utilities" aria-label="Permalink to &quot;4. Utilities&quot;">​</a></h4><p>utilities下提供的各种方法更像是各种各样的工具，比较常用的有对BigNumber的操作，以太坊Token单位的直接转换以及将string于bytes32相互转化的工具等，以下列出几个常见方法</p><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// BigNumber</span></span>
<span class="line"><span style="color:#E5C07B;">BigNumber</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">toNumber</span><span style="color:#ABB2BF;">() </span><span style="color:#C678DD;">=&gt;</span><span style="color:#E06C75;"> number</span></span>
<span class="line"><span style="color:#E5C07B;">BigNumber</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">toHexString</span><span style="color:#ABB2BF;">() </span><span style="color:#C678DD;">=&gt;</span><span style="color:#E06C75;"> string</span><span style="color:#56B6C2;">&lt;</span><span style="color:#E06C75;">DataHexString</span><span style="color:#56B6C2;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Display Logic and Input</span></span>
<span class="line"><span style="color:#E5C07B;">ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">utils</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">parseEther</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">string</span><span style="color:#ABB2BF;">) </span><span style="color:#C678DD;">=&gt;</span><span style="color:#E06C75;"> BigNumber</span></span>
<span class="line"><span style="color:#E5C07B;">ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">utils</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">formatEther</span><span style="color:#ABB2BF;">(</span><span style="color:#61AFEF;">value</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">BigNumber</span><span style="color:#ABB2BF;">)) </span><span style="color:#C678DD;">=&gt;</span><span style="color:#E06C75;"> string</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// Strings</span></span>
<span class="line"><span style="color:#E5C07B;">ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">utils</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">parseBytes32String</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">aBytesLike</span><span style="color:#ABB2BF;">) </span><span style="color:#C678DD;">=&gt;</span><span style="color:#E06C75;"> string</span></span>
<span class="line"><span style="color:#E5C07B;">ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">utils</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">formatBytes32String</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">text</span><span style="color:#ABB2BF;">) </span><span style="color:#C678DD;">=&gt;</span><span style="color:#E06C75;"> string</span><span style="color:#56B6C2;">&lt;</span><span style="color:#E06C75;">DataHexString</span><span style="color:#56B6C2;">&lt;</span><span style="color:#D19A66;">32</span><span style="color:#56B6C2;">&gt;&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br></div></div><ol><li><strong>BigNumber.toNumber()</strong>：将BigNumber的值转换为JavaScript值</li><li><strong>BigNumber.toHexString()</strong>：将BigNumber值转换为0x开头，16进制的值</li><li><strong>ethers.utils.parseEther(string)</strong>：将一个整数转换为以ether为单位的大整数</li><li><strong>ethers.utils.formatEther(value(BigNumber))</strong>：将大整数转换为以ether为单位的整数</li><li><strong>ethers.utils.parseBytes32String(aBytesLike)</strong>：返回一个bytes 32编码数据表示的解码字符串</li><li><strong>ethers.utils.formatBytes32String(text)</strong>：返回文本的bytes 32字符串表示形式</li></ol><h4 id="hardhat-ethers升级接口" tabindex="-1">hardhat-ethers升级接口 <a class="header-anchor" href="#hardhat-ethers升级接口" aria-label="Permalink to &quot;hardhat-ethers升级接口&quot;">​</a></h4><p>使用原生Ethers.js库进行与节点进行交互时，特别在部署合约方面的接口使用中，会发现原生接口的调用比较麻烦</p><p>因此Hardhat在此方面做了优化，即Hardhat提供了一个hardhat-ethers插件，该插件会提供一个ethers对象，该对象与Ethers.js有着相同的API，同时还有一些Hardhat特别定义的接口</p><p>其特别定义的接口主要体现在以下是三个方面：</p><ul><li>不需要额外定义provider，provider已经在执行npx hardhat --network NET run SCRIPT 命令时已自动连接到了选定网络中</li><li>getSigner() =&gt; Signer，该接口直接在hardhat配置中获取signer，不需要定义wallet，但需要提前将账户私钥信息填写到Hardhat配置文件中</li><li>getContracFactory(contractName[, signer]) =&gt; contractFactory，该接口简化了原生contractFactory()接口，使得只需要合约的名字即可产生contractFactory对象 以部署一个ERC-20合约为例：</li></ul><div class="language-javascript line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki one-dark-pro vp-code"><code><span class="line"><span style="color:#7F848E;font-style:italic;">// using hardhat-ethers API to deploy an ERC20 contract</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// get signer</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> alith</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> await</span><span style="color:#E5C07B;"> ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">getSigner</span><span style="color:#ABB2BF;">(</span><span style="color:#D19A66;">1</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// deploy contract</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> Token</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> await</span><span style="color:#E5C07B;"> ehters</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">getContractFactory</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;Token&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">alith</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> token</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> await</span><span style="color:#E5C07B;"> Token</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">deploy</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;MoonToken&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;MTK&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">100</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">await</span><span style="color:#E5C07B;"> token</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">deployed</span><span style="color:#ABB2BF;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// using raw ethers.js API to deploy the same ERC20 contract</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// get provider and signer</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> provider</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#E5C07B;"> ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#E5C07B;">providers</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">JsonRpcProvider</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;http://localhost:9933&#39;</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> alith</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#E5C07B;"> ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">Wallet</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">privateKeyAlith</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">provider</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">// deploy contract</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> Token</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> new</span><span style="color:#E5C07B;"> ethers</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">ContractFactory</span><span style="color:#ABB2BF;">(</span><span style="color:#E06C75;">interface</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">bytecode</span><span style="color:#ABB2BF;">, </span><span style="color:#E06C75;">alith</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">const</span><span style="color:#E5C07B;"> token</span><span style="color:#56B6C2;"> =</span><span style="color:#C678DD;"> await</span><span style="color:#E5C07B;"> Token</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">deploy</span><span style="color:#ABB2BF;">(</span><span style="color:#98C379;">&#39;MoonToken&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#98C379;">&#39;MTK&#39;</span><span style="color:#ABB2BF;">, </span><span style="color:#D19A66;">100</span><span style="color:#ABB2BF;">);</span></span>
<span class="line"><span style="color:#C678DD;">await</span><span style="color:#E5C07B;"> token</span><span style="color:#ABB2BF;">.</span><span style="color:#61AFEF;">deployed</span><span style="color:#ABB2BF;">();</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><p>通过上面的代码示例可以很直观的发现，使用hardhat-ethers提供的API在部署合约时会更方便一些</p>`,68),r=[p];function t(o,c,i,y,B,h){return n(),a("div",null,r)}const u=s(l,[["render",t]]);export{b as __pageData,u as default};
